:host([hidden]){display:none}
*{box-sizing:border-box}
.frame{overflow:hidden;border:1px solid var(--_line);border-radius:18px;background:var(--_bg);box-shadow:0 12px 32px rgba(15,23,42,.07)}
.heading{display:flex;gap:18px;align-items:flex-end;justify-content:space-between;padding:22px 24px 20px;border-bottom:1px solid var(--_line);background:var(--_soft)}
.eyebrow{margin:0 0 6px;color:var(--_accent);font-size:11px;font-weight:800;letter-spacing:.13em;text-transform:uppercase}
h2{margin:0;font-size:clamp(20px,3vw,27px);font-weight:750;letter-spacing:-.025em;line-height:1.2}
.summary{color:var(--_muted);font-size:12px;font-weight:700;white-space:nowrap}
.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(235px,1fr));gap:14px;padding:20px}
.card{min-width:0;padding:17px;border:1px solid var(--_line);border-radius:14px;background:var(--_raised)}
.card-top{display:flex;align-items:flex-start;gap:10px;justify-content:space-between}
.label{font-size:14px;font-weight:740;line-height:1.35}
