  'on-track':{label:'On track',icon:'✓',tone:'var(--_ok)'},
  'done':{label:'Done',icon:'✓',tone:'var(--_ok)'},
  'at-risk':{label:'At risk',icon:'!',tone:'var(--_partial)'},
  'blocked':{label:'Blocked',icon:'✗',tone:'var(--_no)'}
};
