    top.appendChild(make('div','label',item&&item.label!=null?String(item.label):'Untitled metric')); top.appendChild(make('span','pill '+status,info.icon+' '+info.label)); card.appendChild(top);
    const display=item&&item.display!=null?String(item.display):(Math.round(pct)+'%'); const kind=item&&item.kind==='ring'?'ring':'bar';
