      const copy=make('div','metric-copy'); copy.appendChild(make('div','display',display)); copy.appendChild(make('div','fraction',String(value)+' of '+String(max))); if(item&&item.detail) copy.appendChild(make('div','detail',String(item.detail))); metric.appendChild(copy); card.appendChild(metric);
    }else{
      const metric=make('div','metric-row bar-kind'); const meta=make('div','bar-meta'); meta.appendChild(make('span','display',display)); meta.appendChild(make('span','fraction',String(value)+' / '+String(max))); metric.appendChild(meta);
      const track=make('div','bar-track'); track.setAttribute('role','progressbar'); track.setAttribute('aria-valuemin','0'); track.setAttribute('aria-valuemax',String(max)); track.setAttribute('aria-valuenow',String(value)); const fill=make('div','bar-fill'); fill.style.width=pct+'%'; fill.style.setProperty('--tone',info.tone); track.appendChild(fill); metric.appendChild(track); if(item&&item.detail) metric.appendChild(make('div','detail',String(item.detail))); card.appendChild(metric);
